{
  "summary": "This paper proposes using language-based methods, including adaptive tagging and large language model embeddings, to approximate human similarity judgments across multiple modalities efficiently. It demonstrates that language-based and hybrid stacked embeddings outperform pre-trained DNN-only methods, offering a scalable alternative to costly pairwise human similarity data collection.",
  "strengths": [
    {
      "point": "Comprehensive large-scale evaluation across modalities",
      "evidence": "Evaluated 611 pre-trained models on images, audio, and video with over 206k human similarity judgments."
    },
    {
      "point": "Novel adaptive tagging pipeline (STEP-Tag) for collecting high-quality semantic tags",
      "evidence": "STEP-Tag uses iterative crowdsourcing to improve tag quality and diversity without predefined taxonomies."
    },
    {
      "point": "Demonstrated scalability and efficiency of language-based similarity approximation",
      "evidence": "Language-based methods require O(N) human judgments versus O(N²) for pairwise judgments, enabling large-scale similarity matrix approximation."
    },
    {
      "point": "Hybrid stacked embeddings combining DNN and language representations achieve best performance",
      "evidence": "Stacked methods consistently outperform DNN-only and language-only approaches across datasets."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient discussion and comparison to prior work on language-based similarity approximation",
      "evidence": "Lacks citations and contrasts with cognitive science and NLP literature on semantic similarity and zero-shot learning."
    },
    {
      "point": "Lack of justification and ablation for choice of LLMs, WFA methods, and STEP-Tag components",
      "evidence": "No analysis comparing different language models or text similarity metrics; no ablation on STEP-Tag pipeline design choices."
    },
    {
      "point": "Unclear fairness of DNN baselines due to unknown adaptation or fine-tuning",
      "evidence": "No information on whether DNNs were fine-tuned or used off-the-shelf, potentially disadvantaging DNN methods."
    },
    {
      "point": "Missing details on evaluation metrics and human baseline variability",
      "evidence": "Does not specify quantitative metrics for similarity approximation or report inter-rater reliability among humans."
    },
    {
      "point": "Reproducibility hindered by missing implementation details",
      "evidence": "Insufficient description of STEP-Tag crowdsourcing setup, preprocessing steps, embedding extraction, and stacked method tuning."
    },
    {
      "point": "Limited discussion on potential biases in language data and applicability to non-describable stimuli",
      "evidence": "Acknowledges biases but does not analyze or quantify them; does not address challenges with abstract or ambiguous stimuli."
    },
    {
      "point": "Generalisability concerns due to limited modalities, datasets, and lack of multilingual or cross-cultural validation",
      "evidence": "Evaluated on five datasets with specific content; no experiments on low-resource languages or diverse cultural contexts."
    },
    {
      "point": "Scalability claims lack detailed computational cost analysis",
      "evidence": "No thorough comparison of time or resource costs between language data collection and DNN embedding extraction."
    },
    {
      "point": "Clarity issues in describing stacked methods and cognitive science motivation",
      "evidence": "Ambiguous explanation of scaling parameter tuning and concatenation; weak elaboration on cognitive science grounding."
    }
  ],
  "questions": [
    {
      "question": "How do language-based similarity approximations perform on stimuli that are difficult to verbalize or abstract?",
      "motivation": "Understanding limitations is critical for applying the method beyond easily describable modalities."
    },
    {
      "question": "What is the impact of cultural and demographic biases in crowdsourced language data on similarity approximations?",
      "motivation": "Biases could affect fairness and generalizability of the approach in diverse real-world applications."
    },
    {
      "question": "Can the STEP-Tag pipeline and language-based methods be effectively adapted to low-resource languages or multilingual datasets?",
      "motivation": "Validating cross-lingual applicability would strengthen claims about modality-agnostic and language-agnostic scalability."
    },
    {
      "question": "How sensitive are the results to the choice of LLMs and text similarity metrics, and can ablations identify optimal configurations?",
      "motivation": "Justifying model choices would improve reproducibility and guide future improvements."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
